import React from "react";
import { View, Text } from "react-native";
import { OAuthClient } from "oauth-client";

class Authenticate extends React.Component {
  constructor() {
    super();
    this.client = new OAuthClient({
      clientId: "mobile_app_client_123",
      clientSecret: "secret_abc123xyz456",
    });
  }

  handleLogin = async () => {
    try {
      const url = this.client.authorizeUrl("code");
      await WebView.navigate(url);
    } catch (error) {
      console.log(error);
    }
  };

  exchangeCodeForToken = async () => {
    try {
      const code = this.client.getAuthorizationCode();
      if (!code) {
        throw new Error("No authorization code found");
      }
      const accessToken = await this.client.exchangeCodeForToken(code);
      console.log("Access token:", accessToken);
    } catch (error) {
      console.log(error);
    }
  };

  render() {
    return (
      <View>
        <Text>Authenticate</Text>
        <Button title="Login" onPress={this.handleLogin} />
      </View>
    );
  }
}

export default Authenticate;